mapper.select:
SELECT user_id AS userId, role_id AS roleId, NAME AS userName, email, phone, address, created_at AS createdAt, birth FROM user
role_id = #{roleType}
AND NAME LIKE CONCAT('%', #{searchWord}, '%')
ORDER BY roleId LIMIT #{beginRow}, #{rowPerPage}

SELECT COUNT(*) FROM user
role_id = #{roleType}
AND NAME LIKE CONCAT('%', #{searchWord}, '%')

SELECT COUNT(*) FROM notice
target_role_id = #{roleType}
AND title LIKE CONCAT('%', #{searchWord}, '%')

SELECT n.notice_id AS noticeId, n.title, n.content, r.role_name AS roleName, DATE_FORMAT(n.created_at, '%Y-%m-%d') AS createdAt FROM notice n INNER JOIN role r ON r.role_id = n.target_role_id
n.target_role_id = #{roleType}
AND n.title LIKE CONCAT('%', #{searchWord}, '%')
ORDER BY n.created_at DESC LIMIT #{beginRow}, #{rowPerPage}

mapper.update:
UPDATE user
role_id = #{roleId}, email = #{email}, name = #{userName}, phone = #{phone}, address = #{address}, birth = #{birth},
WHERE user_id = #{userId}

UPDATE teacher_history
last_education = #{lastEducation}, personal_history = #{personalHistory},
WHERE teacher_id = #{teacherId}

UPDATE vehicle
vehicle_no = #{vehicleNo}, capacity = #{capacity},
WHERE vehicle_id = #{vehicleId}

	UPDATE vehicle_assignment

        lecture_id = #{lectureId},
        vehicle_id = #{vehicleId},
        location = #{location},
        driver_id = #{driverId}

    WHERE assignment_id = #{assignmentId}

UPDATE notice
title = #{title}, content = #{content}, target_role_id = #{targetRoleId},
WHERE notice_id = #{noticeId}

UPDATE qna
admin_id = #{adminId}, answer = #{answer}, answered_at = NOW()
WHERE qna_id = #{qnaId}

